namespace sv_c8219424a0374b5d9d1992afdf009e38.Client.Models;

public sealed class Shipment
{
    public required string TrackingNumber { get; init; }
    public required string Status { get; init; }
    public required string Location { get; init; }
    public required DateTimeOffset EstimatedDelivery { get; init; }
    public required IReadOnlyList<StatusUpdate> StatusUpdates { get; init; }
}

public sealed class StatusUpdate
{
    public required DateTimeOffset Timestamp { get; init; }
    public required string Description { get; init; }
}

using sv_c8219424a0374b5d9d1992afdf009e38.Client.Models;

namespace sv_c8219424a0374b5d9d1992afdf009e38.Client.Services;

public interface IShipmentService
{
    Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct);
}

using System.Net.Http.Json;
using sv_c8219424a0374b5d9d1992afdf009e38.Client.Models;

namespace sv_c8219424a0374b5d9d1992afdf009e38.Client.Services;

/// <summary>
/// Used when running on WebAssembly — calls the server API over HTTP.
/// </summary>
public sealed class HttpShipmentService(HttpClient http) : IShipmentService
{
    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        var response = await http.GetAsync($"api/shipments/{Uri.EscapeDataString(trackingNumber)}", ct);

        if (response.StatusCode == System.Net.HttpStatusCode.NotFound)
            return null;

        response.EnsureSuccessStatusCode();
        return await response.Content.ReadFromJsonAsync<Shipment>(ct);
    }
}

using sv_c8219424a0374b5d9d1992afdf009e38.Client.Models;
using sv_c8219424a0374b5d9d1992afdf009e38.Client.Services;

namespace sv_c8219424a0374b5d9d1992afdf009e38.Services;

/// <summary>
/// Server-side implementation that simulates a slow backend with seeded data.
/// </summary>
public sealed class ServerShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> Seeds = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-1001"] = new Shipment
        {
            TrackingNumber = "TRK-1001",
            Status = "In Transit",
            Location = "Memphis, TN",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 26, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 20, 8, 0, 0, TimeSpan.Zero), Description = "Package picked up" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 21, 14, 30, 0, TimeSpan.Zero), Description = "Arrived at sorting facility — Memphis, TN" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 22, 6, 15, 0, TimeSpan.Zero), Description = "In transit to destination" },
            ]
        },
        ["TRK-2002"] = new Shipment
        {
            TrackingNumber = "TRK-2002",
            Status = "Delivered",
            Location = "Seattle, WA",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 21, 12, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 18, 9, 0, 0, TimeSpan.Zero), Description = "Package picked up" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 19, 11, 0, 0, TimeSpan.Zero), Description = "Arrived at regional hub" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 20, 16, 45, 0, TimeSpan.Zero), Description = "Out for delivery" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 21, 10, 20, 0, TimeSpan.Zero), Description = "Delivered — signed by J. Smith" },
            ]
        },
        ["TRK-3003"] = new Shipment
        {
            TrackingNumber = "TRK-3003",
            Status = "Processing",
            Location = "Los Angeles, CA",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 28, 18, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 22, 15, 0, 0, TimeSpan.Zero), Description = "Order received — preparing shipment" },
            ]
        },
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        Seeds.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

using Microsoft.AspNetCore.Mvc;
using sv_c8219424a0374b5d9d1992afdf009e38.Client.Services;

namespace sv_c8219424a0374b5d9d1992afdf009e38.Controllers;

[ApiController]
[Route("api/[controller]")]
public class ShipmentsController(IShipmentService shipmentService) : ControllerBase
{
    [HttpGet("{trackingNumber}")]
    public async Task<IActionResult> Get(string trackingNumber, CancellationToken ct)
    {
        var shipment = await shipmentService.GetShipmentAsync(trackingNumber, ct);
        return shipment is null ? NotFound() : Ok(shipment);
    }
}

@page "/shipments/{TrackingNumber}"
@rendermode InteractiveAuto
@using sv_c8219424a0374b5d9d1992afdf009e38.Client.Models
@using sv_c8219424a0374b5d9d1992afdf009e38.Client.Services
@implements IDisposable
@inject IShipmentService ShipmentService
@inject ILogger<ShipmentTracker> Logger

@if (_loading)
{
    <div class="loading-placeholder">
        <p><em>Loading shipment @TrackingNumber&hellip;</em></p>
    </div>
}
else if (_errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <p>@_errorMessage</p>
        <button class="btn btn-outline-danger" @onclick="RetryAsync">Retry</button>
    </div>
}
else if (_shipment is null)
{
    <div class="alert alert-warning" role="alert">
        <p>No shipment found for tracking number <strong>@TrackingNumber</strong>.</p>
    </div>
}
else
{
    <h2>Shipment @_shipment.TrackingNumber</h2>

    <dl>
        <dt>Status</dt>
        <dd>@_shipment.Status</dd>

        <dt>Location</dt>
        <dd>@_shipment.Location</dd>

        <dt>Estimated Delivery</dt>
        <dd>@_shipment.EstimatedDelivery.ToString("f")</dd>
    </dl>

    <h3>Status Updates</h3>
    <table class="table">
        <thead>
            <tr>
                <th>Time</th>
                <th>Description</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var update in _shipment.StatusUpdates)
            {
                <tr>
                    <td>@update.Timestamp.ToString("g")</td>
                    <td>@update.Description</td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [Parameter]
    public string TrackingNumber { get; set; } = string.Empty;

    private Shipment? _shipment;
    private bool _loading;
    private string? _errorMessage;

    private CancellationTokenSource? _cts;

    protected override async Task OnParametersSetAsync()
    {
        await LoadShipmentAsync();
    }

    private async Task LoadShipmentAsync()
    {
        // Cancel any in-flight request when the tracking number changes or on retry.
        _cts?.Cancel();
        _cts?.Dispose();
        _cts = new CancellationTokenSource();
        var ct = _cts.Token;

        _shipment = null;
        _errorMessage = null;
        _loading = true;
        StateHasChanged();

        try
        {
            _shipment = await ShipmentService.GetShipmentAsync(TrackingNumber, ct);
        }
        catch (OperationCanceledException) when (ct.IsCancellationRequested)
        {
            // Navigation changed or component disposed — nothing to render.
            return;
        }
        catch (TaskCanceledException)
        {
            Logger.LogError("Request for shipment {TrackingNumber} timed out", TrackingNumber);
            _errorMessage = $"The request for shipment {TrackingNumber} timed out. Please try again.";
        }
        catch (TimeoutException)
        {
            Logger.LogError("Request for shipment {TrackingNumber} timed out", TrackingNumber);
            _errorMessage = $"The request for shipment {TrackingNumber} timed out. Please try again.";
        }
        catch (Exception ex)
        {
            Logger.LogError(ex, "Failed to load shipment {TrackingNumber}", TrackingNumber);
            _errorMessage = $"Something went wrong while loading shipment {TrackingNumber}. Please try again.";
        }
        finally
        {
            _loading = false;
            StateHasChanged();
        }
    }

    private async Task RetryAsync()
    {
        await LoadShipmentAsync();
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

