namespace sv_c8219424a0374b5d9d1992afdf009e38.Services;

/// <summary>
/// Server-side implementation that simulates a slow backend with seeded data.
/// </summary>
public sealed class ServerShipmentService : IShipmentService
{
    private static readonly Dictionary<string, Shipment> Seeds = new(StringComparer.OrdinalIgnoreCase)
    {
        ["TRK-1001"] = new Shipment
        {
            TrackingNumber = "TRK-1001",
            Status = "In Transit",
            Location = "Memphis, TN",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 26, 17, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 20, 8, 0, 0, TimeSpan.Zero), Description = "Package picked up" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 21, 14, 30, 0, TimeSpan.Zero), Description = "Arrived at sorting facility — Memphis, TN" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 22, 6, 15, 0, TimeSpan.Zero), Description = "In transit to destination" },
            ]
        },
        ["TRK-2002"] = new Shipment
        {
            TrackingNumber = "TRK-2002",
            Status = "Delivered",
            Location = "Seattle, WA",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 21, 12, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 18, 9, 0, 0, TimeSpan.Zero), Description = "Package picked up" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 19, 11, 0, 0, TimeSpan.Zero), Description = "Arrived at regional hub" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 20, 16, 45, 0, TimeSpan.Zero), Description = "Out for delivery" },
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 21, 10, 20, 0, TimeSpan.Zero), Description = "Delivered — signed by J. Smith" },
            ]
        },
        ["TRK-3003"] = new Shipment
        {
            TrackingNumber = "TRK-3003",
            Status = "Processing",
            Location = "Los Angeles, CA",
            EstimatedDelivery = new DateTimeOffset(2026, 5, 28, 18, 0, 0, TimeSpan.Zero),
            StatusUpdates =
            [
                new StatusUpdate { Timestamp = new DateTimeOffset(2026, 5, 22, 15, 0, 0, TimeSpan.Zero), Description = "Order received — preparing shipment" },
            ]
        },
    };

    public async Task<Shipment?> GetShipmentAsync(string trackingNumber, CancellationToken ct)
    {
        await Task.Delay(1500, ct);

        Seeds.TryGetValue(trackingNumber, out var shipment);
        return shipment;
    }
}

using Microsoft.AspNetCore.Mvc;
